/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The total length of any path is (m - 1) + (n - 1) + 1 = m + n - 1.
    // Since m*n <= 1000, the path length is at most 1000.
    // The values are up to 1023 (10 bits).
    // The maximum possible XOR result is less than 1024.

    // We can use Dynamic Programming or BFS/Dijkstra-like approach.
    // Since the path length is fixed (m + n - 1), we can group states by the path length.

    // dp[r][c] will store the set of all possible XOR sums to reach (r, c).
    // However, storing sets might lead to TLE/MLE due to the potentially large number of distinct XOR sums.
    // Given m*n <= 1000 and values <= 1023, the maximum number of distinct XOR sums is 2^10 = 1024.
    // This suggests that keeping a set of possible XOR values might be feasible.

    // dp[r][c] = Set of all achievable XOR sums to reach (r, c).

    const dp = Array(m).fill(0).map(() => Array(n).fill(null).map(() => new Set()));

    // Base case: Start cell (0, 0)
    dp[0][0].add(grid[0][0]);

    // Initialize first row
    for (let c = 1; c < n; c++) {
        const currentVal = grid[0][c];
        for (const xorSum of dp[0][c - 1]) {
            dp[0][c].add(xorSum ^ currentVal);
        }
    }

    // Initialize first column
    for (let r = 1; r < m; r++) {
        const currentVal = grid[r][0];
        for (const xorSum of dp[r - 1][0]) {
            dp[r][0].add(xorSum ^ currentVal);
        }
    }

    // Fill the rest of the DP table
    for (let r = 1; r < m; r++) {
        for (let c = 1; c < n; c++) {
            const currentVal = grid[r][c];

            // From above (r-1, c)
            for (const xorSum of dp[r - 1][c]) {
                dp[r][c].add(xorSum ^ currentVal);
            }

            // From left (r, c-1)
            for (const xorSum of dp[r][c - 1]) {
                dp[r][c].add(xorSum ^ currentVal);
            }
        }
    }

    // The result is the minimum value in the set at (m-1, n-1)
    const finalXorSet = dp[m - 1][n - 1];
    let minXor = 1024; // Max possible value + 1

    for (const xorSum of finalXorSet) {
        if (xorSum < minXor) {
            minXor = xorSum;
        }
    }

    return minXor;
}

